import invariant from '@guanghechen/invariant'
import { GameRunningState } from '@kyokuya/react-game-core'
import cn from 'clsx'
import React, { useEffect, useState } from 'react'
import type { CellClickHandler } from './board'
import SudokuBoardComponent from './board'
import type { CellInputHandler } from './hooks/useCellInputRef'
import useCellInputRef from './hooks/useCellInputRef'
import useHintCell from './hooks/useHintCell'
import useSudokuGameData from './hooks/useSudokuGameData'
import type { SudokuBoardCell } from './types'
import './style.styl'

export interface SudokuGameProps {
  /**
   * Size of the child puzzle matrix (sqrt of original puzzle size).
   * @min 2
   * @max 7
   */
  childMatrixSize: number
  /**
   * Sudoku game running state.
   */
  gameState?: GameRunningState
  /**
   * Game difficulty.
   */
  difficulty?: number
  /**
   * The numeric base used for the numbers displayed in a grid.
   */
  digitalBase?: number
  /**
   * A timestamp to trigger the game refresh.
   */
  gameTick?: number
  /**
   * A timestamp to trigger re-generate hint.
   */
  hintTick?: number
  /**
   * Get the input handle.
   */
  inputRef?: React.RefObject<CellInputHandler>
  /**
   * Sudoku board overlay.
   */
  overlay?: React.ReactNode
  /**
   * The solution Sudo-Board Renderer.
   * @param board
   */
  renderSolutionBoard?(board: React.ReactElement): React.ReactNode
  /**
   * Triggered on a changeable cell clicked.
   */
  onChangeableCellClicked?: CellClickHandler
  /**
   * Triggered when the sudoku solved.
   */
  onGameStateChanged?(finished: boolean): void
}

export const SudokuGame: React.FC<SudokuGameProps> = props => {
  const childMatrixSize = Math.floor(props.childMatrixSize)
  const {
    difficulty,
    gameTick,
    digitalBase,
    gameState,
    hintTick = 0,
    inputRef,
    overlay,
    renderSolutionBoard,
    onChangeableCellClicked,
    onGameStateChanged,
  } = props

  invariant(
    childMatrixSize >= 2 && childMatrixSize <= 7,
    '`childMatrixSize` must be an integer in the range [2, 7].',
  )

  const [activatedPuzzleCell, setActivatedPuzzleCell] =
    useState<SudokuBoardCell>({ r: -1, c: -1 })
  const [activatedSolutionCell, setActivatedSolutionCell] =
    useState<SudokuBoardCell>({ r: -1, c: -1 })

  // Create game data.
  const data = useSudokuGameData(childMatrixSize, difficulty, gameTick)

  // Generate a hint.
  const [hintCell, setHintCell] = useHintCell(
    data,
    hintTick,
    setActivatedPuzzleCell,
  )

  // Create cell input ref
  const gameFinished: boolean = useCellInputRef(
    data,
    setActivatedPuzzleCell,
    setHintCell,
    inputRef,
  )

  useEffect(() => {
    if (onGameStateChanged != null) onGameStateChanged(gameFinished)
  }, [gameFinished])

  useEffect(() => {
    setActivatedPuzzleCell({ r: -1, c: -1 })
    setActivatedSolutionCell({ r: -1, c: -1 })
    if (onGameStateChanged != null) onGameStateChanged(false)
  }, [gameTick, data])

  const handleChangeableCellClicked: CellClickHandler = ({ r, c }, e) => {
    setActivatedPuzzleCell({ r, c })
    if (puzzle[r][c] === -1 && onChangeableCellClicked != null) {
      onChangeableCellClicked({ r, c, v: attempt[r][c] }, e)
    }
  }

  const { puzzle, solution, attempt, segmentNoMap, duplicatedMap } = data
  return (
    <div
      className={cn('sudoku', {
        'sudoku--pending': gameState === GameRunningState.PENDING,
        'sudoku--running': gameState === GameRunningState.RUNNING,
        'sudoku--paused': gameState === GameRunningState.PAUSED,
        'sudoku--finished': gameState === GameRunningState.FINISHED,
      })}
    >
      <SudokuBoardComponent
        className="sudoku-board--puzzle"
        childMatrixSize={childMatrixSize}
        puzzle={puzzle}
        attempt={attempt}
        duplicatedMap={duplicatedMap}
        segmentNoMap={segmentNoMap}
        activatedCell={activatedPuzzleCell}
        onCellClick={handleChangeableCellClicked}
        digitalBase={digitalBase}
        hintGrid={hintCell}
        overlay={overlay}
      />
      {renderSolutionBoard &&
        renderSolutionBoard(
          <SudokuBoardComponent
            className="sudoku-board--solution"
            childMatrixSize={childMatrixSize}
            puzzle={puzzle}
            attempt={solution}
            segmentNoMap={segmentNoMap}
            activatedCell={activatedSolutionCell}
            onCellClick={setActivatedSolutionCell}
            digitalBase={digitalBase}
          />,
        )}
    </div>
  )
}

SudokuGame.displayName = 'SudokuGame'
export default SudokuGame
